export default function icsFormatter() {

    if (navigator.userAgent.indexOf('MSIE') > -1 && navigator.userAgent.indexOf('MSIE 10') === -1) {
        console.log('Unsupported Browser');
        return;
    }

    var SEPARATOR = (navigator.appVersion.indexOf('Win') !== -1) ? '\r\n' : '\n';
    // var SEPARATOR = '\r\n';
    var calendarEvents = [];
    var calendarStart = [
        'BEGIN:VCALENDAR',
        'PRODID:-//1ness//cal_events/NONSGML v1.0//DE',
        'VERSION:2.0'
    ].join(SEPARATOR);
    var calendarEnd = SEPARATOR + 'END:VCALENDAR';

    return {
        /**
         * Returns events array
         * @return {array} Events
         */
        'events': function () {
            return calendarEvents;
        },

        /**
         * Returns calendar
         * @return {string} Calendar in iCalendar format
         */
        'calendar': function () {
            return calendarStart + SEPARATOR + calendarEvents.join(SEPARATOR) + calendarEnd;
        },

        /**
         * Add event to the calendar
         * @param  {string} subject     Subject/Title of event
         * @param  {string} description Description of event
         * @param  {string} location    Location of event
         * @param  {string} begin       Beginning date of event
         * @param  {string} stop        Ending date of event
         */
        'addEvent': function (subject, description, location, begin, stop) {
            // I'm not in the mood to make these optional... So they are all required
            if (typeof subject === 'undefined' ||
                typeof description === 'undefined' ||
                typeof location === 'undefined' ||
                typeof begin === 'undefined' ||
                typeof stop === 'undefined'
            ) {
                return false;
            }

            var start_date = new Date(begin);
            var end_date = new Date(stop);

            var convertDate = function (customDate) {
                var customDate_year = ("0000" + (customDate.getFullYear().toString())).slice(-4);
                var customDate_month = ("00" + ((customDate.getMonth() + 1).toString())).slice(-2);
                var customDate_day = ("00" + ((customDate.getDate()).toString())).slice(-2);
                var customDate_hours = ("00" + (customDate.getUTCHours().toString())).slice(-2);
                var customDate_minutes = ("00" + (customDate.getMinutes().toString())).slice(-2);
                var customDate_seconds = ("00" + (customDate.getMinutes().toString())).slice(-2);
                var customDate_time = 'T' + customDate_hours + customDate_minutes + customDate_seconds + 'Z';
                return customDate_year + customDate_month + customDate_day + customDate_time;
            };

            var uuidv4 = function () {
                return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) {
                    // eslint-disable-next-line no-mixed-operators
                    var r = Math.random() * 16 | 0, v = c === 'x' ? r : (r & 0x3 | 0x8);
                    return v.toString(16);
                });
            };

            var calendarEvent = [
                'BEGIN:VEVENT',
                'UID:' + uuidv4(),
                'CLASS:PUBLIC',
                'DESCRIPTION:' + description,
                'DTSTAMP:' + convertDate(new Date()),
                'DTSTART:' + convertDate(start_date), //start + 'z',
                'DTEND:' + convertDate(end_date), //end + 'z',
                'LOCATION:' + location,
                'SUMMARY:' + subject,
                'TRANSP:TRANSPARENT',
                'END:VEVENT'
            ].join(SEPARATOR);

            calendarEvents.push(calendarEvent);
            return calendarEvent;
        },

        /**
         * Download calendar using the saveAs function from filesave.js
         * @param  {string} filename Filename
         * @param  {string} ext      Extention
         */
        'download': function (filename, ext) {
            if (calendarEvents.length < 1) {
                return false;
            }

            ext = (typeof ext !== 'undefined') ? ext : '.ics';
            filename = (typeof filename !== 'undefined') ? filename : 'calendar';
            var calendar = calendarStart + SEPARATOR + calendarEvents.join(SEPARATOR) + calendarEnd;
            window.open("data:text/calendar;charset=utf-8," + escape(calendar));
        }
    };
};